/**
 * ============================================================
 * DIGITAL LIBRARY — FRONTEND API SERVICE
 * Drop this file into your React project: src/services/api.js
 * ============================================================
 */

const BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

// ─── Token Management ─────────────────────────────────────────────────────────
const getToken = () => localStorage.getItem('accessToken');
const setToken = (token) => localStorage.setItem('accessToken', token);
const removeToken = () => localStorage.removeItem('accessToken');

// ─── Base Fetch Wrapper ───────────────────────────────────────────────────────
const request = async (endpoint, options = {}) => {
  const token = getToken();

  const config = {
    headers: {
      'Content-Type': 'application/json',
      ...(token && { Authorization: `Bearer ${token}` }),
      ...options.headers,
    },
    ...options,
  };

  if (config.body && typeof config.body === 'object') {
    config.body = JSON.stringify(config.body);
  }

  const response = await fetch(`${BASE_URL}${endpoint}`, config);
  const data = await response.json();

  // Auto-handle 401 (token expired)
  if (response.status === 401) {
    removeToken();
    window.dispatchEvent(new CustomEvent('auth:logout'));
    throw new Error(data.message || 'Session expired. Please log in again.');
  }

  if (!response.ok) {
    const error = new Error(data.message || 'Request failed');
    error.errors = data.errors;
    error.statusCode = response.status;
    throw error;
  }

  return data;
};

// ─── Convenience Methods ──────────────────────────────────────────────────────
const get = (endpoint, params) => {
  const query = params ? '?' + new URLSearchParams(params).toString() : '';
  return request(`${endpoint}${query}`, { method: 'GET' });
};
const post = (endpoint, body) => request(endpoint, { method: 'POST', body });
const put = (endpoint, body) => request(endpoint, { method: 'PUT', body });
const patch = (endpoint, body) => request(endpoint, { method: 'PATCH', body });
const del = (endpoint) => request(endpoint, { method: 'DELETE' });

// ─── AUTH API ─────────────────────────────────────────────────────────────────
export const authAPI = {
  register: (data) => post('/auth/register', data),
  login: async (data) => {
    const res = await post('/auth/login', data);
    if (res.data?.accessToken) setToken(res.data.accessToken);
    return res;
  },
  logout: async () => {
    await post('/auth/logout');
    removeToken();
  },
  getMe: () => get('/auth/me'),
  updateMe: (data) => put('/auth/me', data),
  changePassword: (data) => put('/auth/change-password', data),
  refreshToken: (refreshToken) => post('/auth/refresh', { refreshToken }),
};

// ─── BOOKS API ────────────────────────────────────────────────────────────────
export const booksAPI = {
  getAll: (params) => get('/books', params),
  // params: { page, limit, search, genre, author, available, sort }
  getById: (id) => get(`/books/${id}`),
  getGenres: () => get('/books/genres'),
  add: (data) => post('/books', data),
  update: (id, data) => put(`/books/${id}`, data),
  delete: (id) => del(`/books/${id}`),
  getHistory: (id, params) => get(`/books/${id}/history`, params),
};

// ─── LIBRARY CARDS API ────────────────────────────────────────────────────────
export const libraryCardsAPI = {
  apply: (data) => post('/library-cards/apply', data),
  getMyCard: () => get('/library-cards/my-card'),
  getAll: (params) => get('/library-cards', params),
  // params: { page, limit, status, search }
  getStats: () => get('/library-cards/stats'),
  getById: (id) => get(`/library-cards/${id}`),
  review: (id, data) => patch(`/library-cards/${id}/review`, data),
  // data: { status: 'approved'|'rejected', rejectionReason?, bookLimit? }
  suspend: (id, data) => patch(`/library-cards/${id}/suspend`, data),
  reactivate: (id) => patch(`/library-cards/${id}/reactivate`),
};

// ─── ISSUE RECORDS API ────────────────────────────────────────────────────────
export const issuesAPI = {
  issueBook: (data) => post('/issues/issue', data),
  // data: { bookId, studentId, condition? }
  returnBook: (data) => post('/issues/return', data),
  // data: { issueRecordId, condition?, notes? }
  getAll: (params) => get('/issues', params),
  // params: { page, limit, status, studentId, bookId }
  getById: (id) => get(`/issues/${id}`),
  getOverdue: (params) => get('/issues/overdue', params),
  renew: (id) => post(`/issues/${id}/renew`),
};

// ─── FINES API ────────────────────────────────────────────────────────────────
export const finesAPI = {
  getAll: (params) => get('/fines', params),
  getMyFines: (params) => get('/fines/my-fines', params),
  getStats: () => get('/fines/stats'),
  getById: (id) => get(`/fines/${id}`),
  recordPayment: (id, data) => patch(`/fines/${id}/pay`, data),
  // data: { amount, paymentMethod, paymentReference? }
  waive: (id, data) => patch(`/fines/${id}/waive`, data),
  // data: { reason }
  sendReminders: () => post('/fines/send-reminders'),
};

// ─── USERS API ────────────────────────────────────────────────────────────────
export const usersAPI = {
  getAll: (params) => get('/users', params),
  getStudents: (params) => get('/users/students', params),
  getById: (id) => get(`/users/${id}`),
  update: (id, data) => put(`/users/${id}`, data),
  deactivate: (id) => del(`/users/${id}`),
};

// ─── ADMIN API ────────────────────────────────────────────────────────────────
export const adminAPI = {
  getDashboard: () => get('/admin/dashboard'),
  getIssueReport: (params) => get('/admin/reports/issues', params),
  getRecentActivity: () => get('/admin/activity'),
};

// ─── HEALTH CHECK ─────────────────────────────────────────────────────────────
export const healthCheck = () => get('/health');
